func (bl *BeeLogger) Write(p []byte) (n int, err error) {
	if len(p) == 0 {
		return 0, nil
	}

	if p[len(p)-1] == '\n' {
		p = p[0 : len(p)-1]
	}
	lm := &LogMsg{
		Msg:	string(p),
		Level:	levelLoggerImpl,
		When:	time.Now(),
	}

	err = bl.writeMsg(lm)
	if err == nil {
		return len(p), nil
	}
	return 0, err
}
